final:
module RefModule
(
  input  [7:0] data_in,
  input  clk,
  input  load,
  output serial_out
);

reg [7:0] unused_shift_reg;

always @(posedge clk) begin
  if (load)
    unused_shift_reg <= data_in;
  else
    unused_shift_reg <= {1'b0, unused_shift_reg[7:1]};
end

assign serial_out = unused_shift_reg[0];

endmodule
